cd /tmp/sv-6f27111f977a4410a74ba1d8bcb33eca/moderate-msbuild-properties && dotnet list Platform.sln package --format json > after-cpm-packages.json 2>/dev/null && python3 -c "
import json
with open('baseline-packages.json') as f: base = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)
def pkg_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                m[(name, pkg['id'])] = pkg['resolvedVersion']
    return m
b, a = pkg_map(base), pkg_map(after)
print('=== Comparison ===')
for k in sorted(set(list(b.keys()) + list(a.keys()))):
    bv, av = b.get(k, 'MISSING'), a.get(k, 'MISSING')
    status = 'UNCHANGED' if bv == av else f'CHANGED {bv} -> {av}'
    print(f'{k[0]:15} {k[1]:50} {bv:10} {av:10} {status}')
"

